mapper.select:
SELECT id, customer_name AS customerName, order_id AS orderId, schedule_time AS scheduleTime, scheduler, reimburse_type AS reimburseType, reimburse_count AS reimburseCount, produce_ids AS produceIds, status, reimburse_time AS reimburseTime, reimburser, belong_company AS belongCompany, produce_company AS produceCompany, remark, create_user AS createUser, create_time AS createTime FROM yk_reimburse_record
AND customer_name LIKE CONCAT('%', #{query.customerName}, '%')
AND order_id LIKE CONCAT('%', #{query.orderId}, '%')
AND status = #{query.status}
AND reimburse_type = #{query.reimburseType}
ORDER BY create_time DESC
